#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[101];
        scanf("%s", S);
        int N = strlen(S);
        int found = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (S[i] == S[j]) {
                    for (int k = 0; k < N; k++) {
                        for (int l = k + 1; l < N; l++) {
                            if (S[k] == S[l] && (k != i || l != j)) {
                                found = 1;
                                break;
                            }
                        }
                        if (found) break;
                    }
                    if (found) break;
                }
            }
            if (found) break;
        }
        if (found) printf("yes\n");
        else printf("no\n");
    }
    return 0;
}

