    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int N = S.length();
            boolean found = false;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    if (S.charAt(i) == S.charAt(j)) {
                        for (int k = 0; k < N; k++) {
                            for (int l = k + 1; l < N; l++) {
                                if (S.charAt(k) == S.charAt(l) && (k != i || l != j)) {
                                    found = true;
                                    break;
                                }
                            }
                            if (found) break;
                        }
